#include <bits/stdc++.h>
using namespace std;

int n, a[100005];
string s;
long long f[100005];
bool used[256];

int main() {
    cin >> n >> s;
    for (int i = 1; i <= n; i++) {
        cin >> a[i];
    }
    for (int i = 1; i <= n; i++) {
        memset(used, 0, sizeof(used));
        int t;
        for (t = i; t >= 1; t--) {
            if (used[s[t - 1]]) break;
            used[s[t - 1]] = true;
        }
        for (int j = i - 1; j >= t; j--) {
            f[i] = max(f[i], f[j] + a[i - j]);
        }
    }
    cout << f[n];
    return 0;
}
